function calcScorePlantation(data){var score=0;if(data.parcelles.length>0)score+=20;if(data.journalCulture.length>=10)score+=25;else if(data.journalCulture.length>=5)score+=15;else if(data.journalCulture.length>0)score+=5;var hasGps=data.parcelles.some(function(p){return p.lat&&p.lng;});if(hasGps)score+=15;var hasVariete=data.parcelles.some(function(p){return p.variete&&VARIETES[p.variete];});if(hasVariete)score+=10;if(data.journalCulture.length>=20)score+=15;if(data.journalVente.length>=5)score+=15;return Math.min(100,score);}
function calcScoreCredit(data){var score=0;if(data.parcelles.length>0)score+=15;var totalSurface=data.parcelles.reduce(function(s,p){return s+(p.surface||0);},0);if(totalSurface>=5)score+=20;else if(totalSurface>=1)score+=10;if(data.journalCulture.length>=20)score+=25;if(data.journalVente.length>=10)score+=20;var hasGps=data.parcelles.some(function(p){return p.lat&&p.lng;});if(hasGps)score+=10;var hasVariete=data.parcelles.some(function(p){return p.variete;});if(hasVariete)score+=10;return Math.min(100,score);}
function calcScoreEUDR(data){var score=0;var eudr=data.eudr||{};var hasGps=data.parcelles.some(function(p){return p.lat&&p.lng;});if(hasGps||eudr.geolocDone)score+=30;if(eudr.docOrigine)score+=25;if(eudr.traceabilite)score+=20;var hasFermentation=data.journalCulture.some(function(e){return e.type==='fermentation';});if(hasFermentation)score+=15;var hasSurface=data.parcelles.some(function(p){return p.surface&&p.surface>0;});if(hasSurface)score+=10;return Math.min(100,score);}
function scoreColor(score){if(score>=70)return'#2D6A4F';if(score>=40)return'#E8862A';return'#D32F2F';}
function scoreLabel(score){if(score>=70)return'Bon';if(score>=40)return'À améliorer';return'Insuffisant';}
function getPhaseActuelle(){var m=new Date().getMonth()+1;if(m>=10||m<=2)return CALENDRIER[0];if(m>=3&&m<=4)return CALENDRIER[1];if(m>=5&&m<=8)return CALENDRIER[2];return CALENDRIER[3];}
