function getIAFallback(q,data){var totalSurface=data.parcelles.reduce(function(s,p){return s+(p.surface||0);},0);var prixActuel=PRIX_CACAO[PRIX_CACAO.length-1];if(q.match(/phytophthora|pourriture|brun|cabosse.?noire|champignon|fongicide|cuivre/)){return'<b>Pourriture brune (Phytophthora palmivora/megakarya)</b> — Principale maladie du cacao UEMOA.<br>'+'<b>Symptômes :</b> Taches brun-noirâtres sur cabosses, progression rapide, mycélium blanc par temps humide.<br>'+'<b>Traitement préventif (clé) :</b><br>'+'- Fongicide cuivré (Kocide 2000, Funguran OH) toutes les <b>3 semaines</b> en saison humide.<br>'+'- Enlever et enfouir les cabosses malades — ne pas les laisser au sol.<br>'+'- Taille pour aérer la canopée (réduire humidité).<br>'+'- Variétés tolérantes : CCN51, hybrides CNRA.<br>'+'<b>Attention :</b> P. megakarya (Afrique) est plus agressif que P. palmivora — intervenir dès les premiers symptômes.';}
if(q.match(/miride|capside|sahlbergella|distantiella|insecte|larve|rameau|piqure|pousses/)){return'<b>Mirides (Sahlbergella singularis)</b> — 2ème ravageur majeur cacao UEMOA.<br>'+'<b>Symptômes :</b> Lésions nécrotiques sur rameaux, dépérissement "balai de sorcière", mort des apex.<br>'+'<b>Traitement :</b><br>'+'- Insecticide systémique : <b>lambda-cyhalothrine</b> (Karate Zeon) ou <b>imidaclopride</b> (Confidor).<br>'+'- <b>2 traitements minimum/an</b> : novembre-décembre ET mars-avril.<br>'+'- Surveiller les densités de population avant de traiter.<br>'+'- Alternative biologique : fourmis <i>Oecophylla longinoda</i> (méthode traditionnelle efficace).<br>'+'Dégâts cumulatifs sur 2-3 ans — agir tôt !';}
if(q.match(/cssv|swollen.?shoot|virus|cochenille|planococcus|renflement|chlorose/)){return'<b>CSSV — Cocoa Swollen Shoot Virus</b> — Maladie virale, pas de traitement curatif.<br>'+'<b>Symptômes :</b> Renflement racines et tiges, chlorose en bandes rouges sur feuilles, déformation apex.<br>'+'<b>Action obligatoire :</b><br>'+'- <b>Éradication</b> immédiate des arbres malades (coupé-brûlé).<br>'+'- Signalement aux autorités : Cocobod (Ghana), MESSA (Togo), CGFCC (CI).<br>'+'- Lutte contre le vecteur cochenille (Planococcus citri) : insecticides.<br>'+'- Replantation avec matériel sain certifié CNRA/Cocobod.<br>'+'<b>Présence confirmée :</b> Ghana (zones Volta, Eastern Region), Togo (Akébou, Wawa).';}
if(q.match(/fermentation|fermenter|bo[iî]te|feve|f[eè]ves|acide|aceto/)){return'<b>Fermentation des fèves de cacao</b> — Étape critique pour la qualité.<br>'+'<b>Protocole UEMOA recommandé :</b><br>'+'- Durée : <b>6-7 jours</b> en boîtes de fermentation en bois.<br>'+'- Retournement à J2, J4, J6 pour oxygéner et uniformiser.<br>'+'- Température idéale : 45-50°C (vérification manuelle : fèves chaudes au toucher).<br>'+'- Fèves bien fermentées : couleur brun chocolat à la coupe, odeur vineuse puis acidulée.<br>'+'- Fèves ardoisées (gris-ardoise) = sous-fermentées → amertume, moins bonne qualité.<br>'+'- Fèves violettes = incomplètement fermentées.<br>'+'<b>Attention :</b> La fermentation détermine 60% du profil aromatique final.';}
if(q.match(/s[eé]chage|s[eé]cher|humidit[eé]|solaire|bâche|7.?jours|7%.?humidité/)){return'<b>Séchage des fèves de cacao</b> — Obligatoire pour la qualité et la conservation.<br>'+'<b>Protocole :</b><br>'+'- Durée minimale : <b>7 jours</b> en séchage solaire (sur claies surélevées).<br>'+'- Objectif humidité : <b>< 7%</b> (7,5% max acceptable, > 8% = refus à l\'export).<br>'+'- Retournement 2-3x/jour les 3 premiers jours, puis 1x/jour.<br>'+'- Ne pas sécher directement au sol (contamination, bactéries, moisissures).<br>'+'- En saison des pluies : protéger avec bâche transparente la nuit, retirer le jour.<br>'+'- Mesurer l\'humidité avec un humidimètre de poche avant commercialisation.';}
if(q.match(/prix|vendre|march[eé]|cours|fcfa|eudr|export|eur[eo]pe/)){return'<b>Prix marché cacao UEMOA actuel :</b> '+prixActuel.prix.toLocaleString()+' FCFA/kg ('+prixActuel.mois+')<br>'+'<b>Contexte :</b> Pic historique 2024-2025 (crise mondiale, déficit production). Tendance actuelle à la baisse depuis mars 2025.<br>'+'<b>ICE Futures :</b> ~'+prixActuel.iceUsd.toLocaleString()+' USD/tonne.<br>'+'<b>Pour exporter en Europe (EUDR) :</b><br>'+'- Géolocalisation GPS de chaque parcelle obligatoire.<br>'+'- Document d\'origine traçable (reçu CGFCC, Cocobod, etc.).<br>'+'<b>Seuil d\'alerte :</b> si un acheteur propose moins de '+Math.round(prixActuel.prix*0.75).toLocaleString()+' FCFA/kg, c\'est anormalement bas.<br>'+'Enregistrez chaque vente dans l\'onglet <b>Marché</b>.';}
if(q.match(/vari[eé]te|choisir|kor|beurre|forastero|trinitario|ccn51|cnra|rendement|hybride/)){return'<b>Variétés cacao UEMOA — comparatif :</b><br>'+'- <b>Forastero Amelonado</b> : KOR 38-42%, 400-600 kg/ha. Dominant CI. Sensible Phytophthora.<br>'+'- <b>Trinitario</b> : KOR 44-48%, 500-800 kg/ha. Arôme fin, marché premium (+15-30%).<br>'+'- <b>CCN51</b> : KOR 48-52%, <b>1200-2000 kg/ha</b>. Très résistant, excellent rendement.<br>'+'- <b>Hybride CNRA</b> : KOR 42-46%, 800-1200 kg/ha. Meilleur compromis CI.<br>'+'- <b>Forastero Local</b> : KOR 35-40%, 300-500 kg/ha. Vieilles plantations, renouveler.<br>'+'<b>Recommandation :</b> Pour replanter, préférer les hybrides CNRA (semences Divo) ou CCN51 si marché standard.';}
if(q.match(/calendrier|saison|r[eé]colte|main.?crop|mid.?crop|grande.?r[eé]colte|petite.?r[eé]colte|octobre|novembre/)){return'<b>Calendrier cultural cacao UEMOA :</b><br>'+'- <b>Oct-Fév : Grande récolte (Main Crop)</b> — 60% de la production annuelle. Fermentation + séchage intensifs.<br>'+'- <b>Mar-Avr : Fin grande récolte + interrécolte</b> — Taille, traitement fongicide préventif.<br>'+'- <b>Mai-Août : Petite récolte (Mid Crop)</b> — 40% production. Vigilance Phytophthora (pluies).<br>'+'- <b>Sep-Oct : Entretien</b> — Taille de régénération, fertilisation NPK, replantation vides.<br>'+'<b>Actuellement :</b> Phase <b>'+getPhaseActuelle().phase+'</b> ('+getPhaseActuelle().mois+').';}
if(q.match(/eudr|r[eè]glement|union.?europ[eé]enne|traçabilit[eé]|d[eé]forestation|conformit[eé]/)){return'<b>EUDR — Règlement UE 2023/1115 (déforestation)</b><br>'+'Applicable depuis décembre 2024 pour les opérateurs. Obligatoire pour exporter cacao vers l\'Europe.<br>'+'<b>Obligations producteur :</b><br>'+'1. Géolocalisation GPS de chaque parcelle (polygone ou point).<br>'+'2. Document d\'origine traçable (reçu CGFCC CI, Cocobod Ghana).<br>'+'3. Fiche fermentation + séchage avec dates et humidité mesurée.<br>'+'4. Numéro de lot attribué par l\'exportateur (chaîne producteur → acheteur UE).<br>'+'<b>Pour améliorer votre score EUDR :</b> Géolocalisez vos parcelles dans l\'onglet Journal, cochez doc. origine dans Mon Dossier.';}
if(q.match(/rendement|production|revenu|argent|estimer|bénéfice|tonne.?ha|kg.?ha/)){var prix=prixActuel.prix;return'<b>Niveaux de rendement cacao UEMOA :</b><br>'+'- Forastero vieilles plantations : <b>300-600 kg/ha</b><br>'+'- Hybride CNRA entretenu : <b>800-1200 kg/ha</b><br>'+'- CCN51 en système intensif : <b>1200-2000 kg/ha</b><br>'+
(totalSurface>0?'<br>Sur votre surface ('+totalSurface.toFixed(1)+' ha) au prix actuel ('+prix.toLocaleString()+' FCFA/kg) :<br>'+'- Forastero : <b>'+Math.round(totalSurface*500*prix/1000).toLocaleString()+'k FCFA</b><br>'+'- Hybride CNRA : <b>'+Math.round(totalSurface*1000*prix/1000).toLocaleString()+'k FCFA</b><br>'+'- CCN51 : <b>'+Math.round(totalSurface*1600*prix/1000).toLocaleString()+'k FCFA</b><br>':'')+'<b>Levier principal :</b> Renouvellement variétal (hybrides CNRA/CCN51) + traitement systématique mirides + fermentation soignée.';}
return'Je suis l\'Assistant Agronomique Cacao UEMOA, formé sur les données CNRA, ICCO, WCF et EUDR.<br>'+'Posez-moi des questions sur : les variétés, la fermentation, le séchage, les maladies (Phytophthora, Mirides, CSSV), le calendrier, les prix, ou la conformité EUDR.<br>'+'<b>Exemples :</b> "Ma cabosse est noire", "Comment ferment correctement ?", "Mon score EUDR est bas", "Quelle variété replanter ?", "Prix cacao aujourd\'hui"';}
